CREATE TABLE IF NOT EXISTS account_snapshots (id BIGSERIAL PRIMARY KEY, tenant_id BIGINT NOT NULL REFERENCES tenants(id) ON DELETE CASCADE, instagram_account_id BIGINT NOT NULL REFERENCES instagram_accounts(id) ON DELETE CASCADE, captured_at TIMESTAMPTZ NOT NULL, followers_count BIGINT, follows_count BIGINT, media_count BIGINT, engagement_rate NUMERIC(8,4), source_name TEXT NOT NULL);
